// Regiões do Brasil para filtro
const REGIOES = {
  "Norte":     ["AM","PA","AC","RO","RR","AP","TO"],
  "Nordeste":  ["MA","PI","CE","RN","PB","PE","AL","SE","BA"],
  "Centro-Oeste": ["MT","MS","GO","DF"],
  "Sudeste":   ["SP","RJ","MG","ES"],
  "Sul":       ["PR","SC","RS"],
};

function corPonto(pct) {
  if (pct >= 0.99) return "#16A34A";
  if (pct >= 0.5)  return "#84CC16";
  if (pct > 0)     return "#F59E0B";
  return "#DC2626";
}

// Componente auxiliar para centralizar no Brasil ao resetar
function ResetView() {
  const map = useMap();
  useEffect(() => { map.setView([-15, -55], 4); }, []);
  return null;
}

// Componente auxiliar para dar zoom numa região
function ZoomRegion({ bounds }) {
  const map = useMap();
  useEffect(() => { if (bounds) map.fitBounds(bounds, { padding:[30,30] }); }, [bounds]);
  return null;
}

export default function MapaAbrangencia({ rows, coordCidades }) {
  const [filtroVal,     setFiltroVal]     = useState("Todos");
  const [filtroRegiao,  setFiltroRegiao]  = useState("Todas");
  const [filtroColetas, setFiltroColetas] = useState(0);   // Mínimo de coletas Parça
  const [ufFoco,        setUfFoco]        = useState(null);
  const [resetKey,      setResetKey]      = useState(0);

  // ── Agrega por cidade ──────────────────────────────────────────────────────
  const pontos = useMemo(() => {
    const mapa = new Map();
    rows.forEach(r => {
      const key = `${r.estado}|${r.cidade}`;
      const coord = coordCidades[key];
      if (!coord) return;
      if (!mapa.has(key)) {
        mapa.set(key, { uf: r.estado, cidade: r.cidade, lat: coord[0], lon: coord[1],
          coletasTotal: 0, coletasParca: 0, temParca: false });
      }
      const p = mapa.get(key);
      p.coletasTotal += r.abrangencia;
      if (r.validacao === "PARÇA") { p.coletasParca += r.abrangencia; p.temParca = true; }
    });
    return [...mapa.values()].map(p => ({
      ...p,
      pct: p.coletasTotal > 0 ? p.coletasParca / p.coletasTotal : 0,
      raio: Math.min(22, Math.max(4, Math.sqrt(p.coletasTotal) * 0.6)),
    }));
  }, [rows, coordCidades]);

  // ── Aplica filtros ──────────────────────────────────────────────────────────
  const pontosFiltrados = useMemo(() => {
    const ufsRegiao = filtroRegiao !== "Todas" ? REGIOES[filtroRegiao] : null;
    return pontos.filter(p => {
      if (filtroVal === "PARÇA"     && !p.temParca)           return false;
      if (filtroVal === "NÃO PARÇA" && p.temParca)            return false;
      if (ufsRegiao && !ufsRegiao.includes(p.uf))             return false;
      if (p.coletasParca < filtroColetas)                     return false;
      return true;
    });
  }, [pontos, filtroVal, filtroRegiao, filtroColetas]);

  // Bounds da região selecionada para zoom automático
  const boundsRegiao = useMemo(() => {
    if (filtroRegiao === "Todas") return null;
    const pts = pontosFiltrados;
    if (!pts.length) return null;
    const lats = pts.map(p => p.lat);
    const lons = pts.map(p => p.lon);
    return [[Math.min(...lats)-1, Math.min(...lons)-1], [Math.max(...lats)+1, Math.max(...lons)+1]];
  }, [filtroRegiao, pontosFiltrados]);

  const ufsDisponiveis = useMemo(() => [...new Set(rows.map(r=>r.estado))].sort(), [rows]);

  const maxColetas = useMemo(() => Math.max(...pontos.map(p=>p.coletasParca), 0), [pontos]);

  const geoJsonStyle = () => ({
    color: "#374151", weight: 1.2, fillColor: "#F8FAFC", fillOpacity: 0.4,
  });

  const pill = (ativo) => ({
    padding:"5px 12px", borderRadius:999, fontSize:12, fontWeight:600, cursor:"pointer",
    border:`1.5px solid ${ativo ? C.laranja : C.cinzaBorda}`,
    background: ativo ? `${C.laranja}18` : "transparent",
    color: ativo ? C.laranja : C.cinzaTexto,
  });

  return (
    <div>
      {/* ── Barra de filtros ── */}
      <div style={{ display:"flex", gap:10, marginBottom:14, flexWrap:"wrap", alignItems:"center" }}>
        
        {/* Validação */}
        <div style={{ display:"flex", gap:6, alignItems:"center" }}>
          <span style={{ fontSize:11, fontWeight:700, color:C.cinzaTexto }}>Mostrar:</span>
          {["Todos","PARÇA","NÃO PARÇA"].map(v=>(
            <button key={v} onClick={()=>setFiltroVal(v)} style={pill(filtroVal===v)}>{v}</button>
          ))}
        </div>

        <div style={{ width:1, height:24, background:C.cinzaBorda }} />

        {/* Região */}
        <div style={{ display:"flex", gap:6, alignItems:"center" }}>
          <span style={{ fontSize:11, fontWeight:700, color:C.cinzaTexto }}>Região:</span>
          {["Todas","Norte","Nordeste","Centro-Oeste","Sudeste","Sul"].map(r=>(
            <button key={r} onClick={()=>{ setFiltroRegiao(r); setResetKey(k=>k+1); }} style={pill(filtroRegiao===r)}>{r}</button>
          ))}
        </div>

        <div style={{ width:1, height:24, background:C.cinzaBorda }} />

        {/* Mínimo de coletas Parça */}
        <div style={{ display:"flex", gap:8, alignItems:"center" }}>
          <span style={{ fontSize:11, fontWeight:700, color:C.cinzaTexto }}>Mín. coletas Parça:</span>
          {[0, 5, 10, 20].map(v=>(
            <button key={v} onClick={()=>setFiltroColetas(v)} style={pill(filtroColetas===v)}>
              {v === 0 ? "Todas" : `≥ ${v}`}
            </button>
          ))}
        </div>

        <button onClick={()=>{ setFiltroVal("Todos"); setFiltroRegiao("Todas"); setFiltroColetas(0); setResetKey(k=>k+1); }}
          style={{ marginLeft:"auto", padding:"5px 12px", borderRadius:6, border:`1px solid ${C.cinzaBorda}`, background:"transparent", fontSize:12, cursor:"pointer", color:C.cinzaTexto }}>
          Resetar
        </button>
      </div>

      {/* Contagem de pontos visíveis */}
      <div style={{ fontSize:12, color:C.cinzaTexto, marginBottom:10 }}>
        Exibindo <strong>{pontosFiltrados.length.toLocaleString("pt-BR")}</strong> de {pontos.length.toLocaleString("pt-BR")} cidades
        {filtroRegiao !== "Todas" && <> na região <strong>{filtroRegiao}</strong></>}
        {filtroVal !== "Todos" && <> · validação <strong>{filtroVal}</strong></>}
        {filtroColetas > 0 && <> · mín. <strong>{filtroColetas}</strong> coletas Parça</>}
      </div>

      {/* ── Mapa Leaflet ── */}
      <div style={{ borderRadius:12, overflow:"hidden", border:`1px solid ${C.cinzaBorda}`, boxShadow:"0 2px 8px rgba(0,0,0,0.08)" }}>
        <MapContainer
          key={resetKey}
          center={[-15, -55]}
          zoom={4}
          minZoom={3}
          maxZoom={12}
          style={{ height:580, width:"100%", background:"#EBF4FF" }}
          zoomControl={true}
        >
          {/* Tiles com estilo limpo e claro */}
          <TileLayer
            url="https://{s}.basemaps.cartocdn.com/light_nolabels/{z}/{x}/{y}{r}.png"
            attribution='© <a href="https://www.openstreetmap.org/copyright">OSM</a> © <a href="https://carto.com/">CARTO</a>'
          />

          {/* Contornos dos estados — GeoJSON */}
          <GeoJSON key="geojson" data={BRAZIL_GEOJSON} style={()=>({color:"#94A3B8",weight:1,fillColor:"#F8FAFC",fillOpacity:0.3})} />

          {/* Zoom automático na região filtrada */}
          {boundsRegiao && <ZoomRegion bounds={boundsRegiao} />}

          {/* Pontos das cidades — menores primeiro (debaixo) */}
          {[...pontosFiltrados]
            .sort((a, b) => a.coletasTotal - b.coletasTotal)
            .map((p, i) => (
              <CircleMarker
                key={i}
                center={[p.lat, p.lon]}
                radius={p.raio}
                pathOptions={{
                  fillColor: corPonto(p.pct),
                  fillOpacity: 0.82,
                  color: "#fff",
                  weight: 0.8,
                }}
                eventHandlers={{ click: () => setUfFoco(p.uf) }}
              >
                <Tooltip direction="top" offset={[0,-4]} opacity={0.97}>
                  <div style={{ fontFamily:"Arial,sans-serif", minWidth:160 }}>
                    <div style={{ fontWeight:700, fontSize:13, marginBottom:4 }}>{p.cidade} — {p.uf}</div>
                    <div style={{ fontSize:12 }}>Coletas totais: <strong>{p.coletasTotal.toLocaleString("pt-BR")}</strong></div>
                    <div style={{ fontSize:12 }}>Coletas Parça: <strong>{p.coletasParca.toLocaleString("pt-BR")}</strong></div>
                    <div style={{ fontSize:12 }}>Cobertura: <strong style={{ color: p.pct>=0.5?"#16A34A":"#DC2626" }}>{(p.pct*100).toFixed(0)}%</strong></div>
                  </div>
                </Tooltip>
              </CircleMarker>
            ))
          }
        </MapContainer>
      </div>

      {/* ── Legenda + info ── */}
      <div style={{ display:"flex", gap:20, marginTop:12, alignItems:"center", flexWrap:"wrap" }}>
        <div style={{ display:"flex", gap:14, alignItems:"center", fontSize:12, color:C.cinzaTexto }}>
          {[["#16A34A","100% Parça"],["#84CC16","≥50% Parça"],["#F59E0B","<50% (misto)"],["#DC2626","0% Parça"]].map(([cor,txt])=>(
            <div key={txt} style={{ display:"flex", alignItems:"center", gap:5 }}>
              <div style={{ width:12, height:12, borderRadius:"50%", background:cor }} />{txt}
            </div>
          ))}
          <span style={{ color:C.cinzaTexto }}>● Tamanho = volume de coletas</span>
        </div>
        <div style={{ fontSize:11, color:C.cinzaTexto, marginLeft:"auto" }}>
          Use scroll/pinch para zoom · clique num ponto para filtrar o estado na tabela abaixo
        </div>
      </div>

      {/* ── Painel de detalhe do estado (abaixo do mapa) ── */}
      {ufFoco && (
        <div style={{ marginTop:16, background:C.cinzaCard, border:`1px solid ${C.cinzaBorda}`, borderRadius:12, padding:20 }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
            <div style={{ fontWeight:700, fontSize:14 }}>{ufFoco} — detalhamento por cidade</div>
            <button onClick={()=>setUfFoco(null)} style={{ background:"none", border:"none", cursor:"pointer", color:C.cinzaTexto, fontSize:18 }}>✕</button>
          </div>
          <div style={{ maxHeight:340, overflowY:"auto" }}>
            <table style={{ width:"100%", fontSize:12, borderCollapse:"collapse" }}>
              <thead style={{ position:"sticky", top:0, background:C.cinzaFundo }}>
                <tr style={{ textAlign:"left", color:C.cinzaTexto }}>
                  <th style={{ padding:"6px 8px" }}>Cidade</th>
                  <th style={{ padding:"6px 8px" }}>Transportadora</th>
                  <th style={{ padding:"6px 8px" }}>Validação</th>
                  <th style={{ padding:"6px 8px", textAlign:"right" }}>Coletas ↓</th>
                </tr>
              </thead>
              <tbody>
                {rows
                  .filter(r => r.estado === ufFoco)
                  .sort((a,b) => b.abrangencia - a.abrangencia)
                  .map((r,i) => (
                    <tr key={i} style={{ borderTop:`1px solid ${C.cinzaBorda}` }}>
                      <td style={{ padding:"5px 8px" }}>{r.cidade}</td>
                      <td style={{ padding:"5px 8px" }}>{r.transportadora}</td>
                      <td style={{ padding:"5px 8px", color:r.validacao==="PARÇA"?C.verde:C.vermelho, fontWeight:600 }}>{r.validacao}</td>
                      <td style={{ padding:"5px 8px", textAlign:"right", fontWeight:600 }}>{r.abrangencia}</td>
                    </tr>
                  ))
                }
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
